const packingList = $('Extraction agent').first().json.output;

const replacements = Object.fromEntries(
  candidates.map(c => [c.misreadSku, c.actualSku])
);

for (const lineItem of packingList.line_items) {
  if (lineItem.sku in replacements) {
  lineItem.sku = replacements[lineItem.sku];
}
}

return packingList;

